#include <vector>

bool solve(std::vector<long long> nums) {
    int n = nums.size();
    if (n < 3) return false;

    int p = 1;
    while (p < n - 1 && nums[p] > nums[p - 1]) {
        p++;
    }

    if (p == n - 1) return false;

    int q = p + 1;
    while (q < n && nums[q] < nums[q - 1]) {
        q++;
    }

    if (q == n) return false;

    // Check if the remaining part is strictly increasing
    for (int i = q; i < n; i++) {
        if (nums[i] <= nums[i - 1]) {
            return false;
        }
    }

    return true;
}

